module binary_search_comparator(  
    input [3:0] target,  
    input [3:0] index,  
    output reg found  
);  
    reg [3:0] unused_array [0:15];  
    initial begin  
        // Initialize the unused_array with some values for testing purposes  
        unused_array[0] = 4'b0000;  
        unused_array[1] = 4'b0001;  
        unused_array[2] = 4'b0010;  
        unused_array[3] = 4'b0011;  
        unused_array[4] = 4'b0100;  
        unused_array[5] = 4'b0101;  
        unused_array[6] = 4'b0110;  
        unused_array[7] = 4'b0111;  
        unused_array[8] = 4'b1000;  
        unused_array[9] = 4'b1001;  
        unused_array[10] = 4'b1010;  
        unused_array[11] = 4'b1011;  
        unused_array[12] = 4'b1100;  
        unused_array[13] = 4'b1101;  
        unused_array[14] = 4'b1110;  
        unused_array[15] = 4'b1111;  
    end  

    always @(*) begin  
        found = (unused_array[index] == target);  
    end  
endmodule
